INSERT INTO `festivals` VALUES (1129,'청주시 반려동물 문화행사','충청북도','충청북도 청주시 청원구 내수읍 덕암길 10','20260530','20260530','https://tong.visitkorea.or.kr/cms/resource/91/4065291_image2_1.jpg','축제','무료 (일부 체험부스는 소정의 재료비 발생)','033-813-0333','[이용 요금] 무료 (일부 체험부스는 소정의 재료비 발생)\n[문의처] 033-813-0333\n\n[소개]\n- 주요 프로그램 : 방과후 댕교실 (반려동물에게 보내는 느린 우체통 / 반려견 체질 분석 / 도그마사지 및 아로마 / 심폐소생술 교육 / 멍포차 / 펫베이커리 / 멍슐랭 레스토랑 / 터그놀이 만들기 / 발도장 액자 만들기 / 반려동물 캐리커쳐 / 사회화 교육 / 예절 훈련 / 반려견 위생 미용) \n- 부대 행사 및 프로그램 : 게임프로그램 / 펫티켓 퀴즈 / 동물 상식 대결 / 교복·커플룩 선발대회 / 반려동물 장기자랑 콘테스트 / 반려동물 사진전 / 스탬프 투어(완료 시 졸업사진 촬영) / 프리마켓 / 유기동물 입양 캠페인 / 오프리쉬 존 / 포토존(견생네컷) 등\n\n','2026-05-19 02:20:28','',NULL,NULL),(1130,'꽃멍+물멍, 책자리','충청남도','충청남도 공주시 중동(중학동)','20260516','20260517','https://tong.visitkorea.or.kr/cms/resource/99/4064299_image2_1.jpg','축제','무료','041-840-8955','[이용 요금] 무료\n[문의처] 041-840-8955\n\n[소개]\n1. 메인프로그램 : 야외도서관 \n2. 부대프로그램 : 16일 15:00~16:00 앙상블 솔리 데오 | 18:00~20:00 공주문화관광재단 상설공연(모먼트52, 블낫블)\n3. 소비자 참여 프로그램 : 17일 13:00 ~ 21:00 그리기체험(2026 어반스케치 워크 연계)\n4. 기타 내용 : 공주의 시간 사진으로 잇다 : 지금 여기, 그땐 그랬지 - 공주학연구원 공주학 아카이브 자료 활용\n\n','2026-05-19 02:20:41','',NULL,NULL),(1131,'반가운축제 (반려견과 가치있게 운동하는 축제)','경기도','경기도 안산시 상록구 해안로 615 (사동)','20260607','20260607','https://tong.visitkorea.or.kr/cms/resource/59/4064359_image2_1.jpg','축제','무료','1533-0799','[이용 요금] 무료\n[문의처] 1533-0799\n\n[소개]\n- 주요 프로그램 : 반려견 걷기대회 / 스피드 독 챌린지 / 멍BTI 체험존 / 멍때리기 대회\n- 부대 행사 및 프로그램 : 어질리티 체험존 / 반려견 상식 OX퀴즈(멍댕 브레인 킹) / 전문가와 함꼐하는 세미나 / 체험부스프로그램 등\n\n','2026-05-19 02:20:46','',NULL,NULL),(1132,'평화온담','경기도','경기도 화성시 동탄구 동탄순환대로 69 (송동)','20260530','20260530','https://tong.visitkorea.or.kr/cms/resource/08/4063708_image2_1.jpg','축제','무료','042-825-6781','[이용 요금] 무료\n[문의처] 042-825-6781\n\n[소개]\n1. 사전 행사: 평화배달키트, 풍선 나눠주기, 퍼포머 행진 버스킹\n2. 체험 프로그램: 히든미션, 뜨개공방, 스트링아트, 바람개비만들기, 네컷사진 등\n3. 공연 프로그램: 버블퍼포먼스, 벌룬퍼포먼스, 디아블로요요, 재즈공연\n4. 그림책방 : 북크닉존, 작가와의 만남, 구연동화 등\n\n','2026-05-19 02:20:51','',NULL,NULL),(1133,'충북 괴산 우주특별시：별별탐사대','충청북도','충청북도 괴산군 괴산읍 충민로검승1길 6','20260430','20261206','https://tong.visitkorea.or.kr/cms/resource/07/4063007_image2_1.jpg','축제','무료','043-299-9314','[이용 요금] 무료\n[문의처] 043-299-9314\n\n[소개]\n1. 제 1 전시실 별별아트 \n- 우주생태\' 가설 기반으로 작가들이 만든 다양한 설치 미술을 경험하는 공간\n- 설치미술, 그래피티, UV아트 사운드 인터랙티브 등 다양한 현대미술 요소를 경험\n\n2. 제 2 전시실 별별놀이 \n- 동화적 상상력으로 은유한 \'은하수\'를 놀이로 통해 인지하며 체험하는 공간\n\n3. 제 3 전시실 별별생각 \n- \'우주는 무한한 상상의 캔버스\'라는 명제로 연출된 다양한 기초 미술 교육 체험 공간\n- 전시를 통해 떠올린 상상과 아이디어를 능동적으로 참여하여 완성하는 창작 활동\n\n','2026-05-19 02:20:55','',NULL,NULL),(1134,'쉼표：비우고, 머무르고, 채우는','경상북도','경상북도 경주시 금성로 260-6 (노서동)','20260321','20260817','https://tong.visitkorea.or.kr/cms/resource/26/4062226_image2_1.jpg','축제','[전시]- 성인(19~64세) 8,000원- 소인(4세~18세) 5,000원- 경로우대자(65세 이상) 5,000원[전시 연계 프로그램]- 전시관람(도슨트)/미술관요가/차담 75,000원- 전시관람(도슨트)/미술관요가/사찰음식런치박스 125,000원','054-705-5501','[이용 요금] [전시]- 성인(19~64세) 8,000원- 소인(4세~18세) 5,000원- 경로우대자(65세 이상) 5,000원[전시 연계 프로그램]- 전시관람(도슨트)/미술관요가/차담 75,000원- 전시관람(도슨트)/미술관요가/사찰음식런치박스 125,000원\n[문의처] 054-705-5501\n\n[소개]\n1. 주요 프로그램 : 전시 \n2. 전시 연계 프로그램 :  (사전예약)\n- 기간 : 2026/05/07~2026/08/11 (8회)\n- 시간 09:30~11:30\n- 프로그램 구성 : 전시 관람(도슨트) / 미술관 요가 / 차담 또는 사찰음식 런치박스\n- 인원 : 15명 내외(12세 이상 참여 가능)\n※ 본 프로그램은 총 8회차로 구성되며, 요가 클래스 및 차담 또는 사찰음식 런치박스는 번갈아 운영\n\n','2026-05-19 02:21:06','',NULL,NULL),(1135,'과천재즈피크닉','경기도','경기도 과천시 관문로 64 (중앙동)','20260501','20260502','https://tong.visitkorea.or.kr/cms/resource/27/4061427_image2_1.jpg','축제','무료','02-2009-9731','[이용 요금] 무료\n[문의처] 02-2009-9731\n\n[소개]\n1. 메인프로그램 : 국내·외 재즈 아티스트 10팀 공연\n2. 부대프로그램 : 음반·서적 판매부스, 사인회, 느린 우체통, 플리마켓, 포토존, 푸드트럭 등\n3. 소비자 참여 프로그램 : 라퍼커션의 바투카다(타악기 퍼포먼스) 행렬, 마담꾸꾸(어린이체험+굿즈)\n\n','2026-05-19 02:21:14','',NULL,NULL),(1136,'제104회 어린이날 기념행사','서울특별시','서울특별시 중구 소공로 106 (소공동)','20260504','20260504','https://tong.visitkorea.or.kr/cms/resource/91/4061391_image2_1.png','축제','무료','02-3463-5020','[이용 요금] 무료\n[문의처] 02-3463-5020\n\n[소개]\n- 주요 프로그램 : 개회선언 / 국민의례  / 유공자 포상 / 공모전 수상작 시상 / 어린이 뮤지컬 축하공연\n- 부대 행사 및 프로그램 : 나만의 키캡 만들기 / 물고기 부채 만들기 /  어린이 공모전 수상작 전시 / LED포토존\n\n','2026-05-19 02:21:25','',NULL,NULL),(1137,'국악공연 진연','서울특별시','서울특별시 종로구 인사동5길 10 (인사동)','20260101','20261231','https://tong.visitkorea.or.kr/cms/resource/35/4060435_image2_1.jpg','공연','- 일반 65,000원- 장애인 50% 할인※ 무료 : 24개월 미만','02-953-0515','[이용 요금] - 일반 65,000원- 장애인 50% 할인※ 무료 : 24개월 미만\n[문의처] 02-953-0515\n\n[소개]\n- 1부 길제 : 공연에 와주신 분들께 정화수를 올리고 이들의 평안한 행복을 정성스레 기원한다.\n- 2부 진연 : 궁중에서 귀한 손님들에게 선보였던 전통공연과 임금에게 올렸던 정악과 악기의 테크닉이 돋보이는 산조를 감상한다.\n- 3부 화합 : 대한민국의 전통악기로 다양한 나라의 음악을 연주하며 예술로 관객과 연주자가 하나되는 시간이다.\n\n','2026-05-19 02:21:30','',NULL,NULL),(1138,'10년후그라운드','광주광역시','광주광역시 남구 양촌길 1 (양림동)','20260101',NULL,'https://tong.visitkorea.or.kr/cms/resource/58/3402458_image2_1.JPG','전시','정보 없음','070-4763-5070','[이용 요금] 정보 없음\n[이용 시간] 정보 없음\n[휴무일] 연중무휴\n[문의처] 070-4763-5070\n\n[소개]\n상세 소개 정보가 준비 중입니다.','2026-05-19 02:21:35','',NULL,NULL),(1139,'어반브룩','광주광역시','광주광역시 남구 임암길 181 (임암동)','20260101',NULL,'https://tong.visitkorea.or.kr/cms/resource/08/4065108_image2_1.jpg','전시','- 킨포크 코스 A 68,000원\n- 킨포크 코스 B 98,000원\n- 어반정식 A 35,000원\n- 어반정식 B 55,000원','062-674-0100','[이용 요금] - 킨포크 코스 A 68,000원\n- 킨포크 코스 B 98,000원\n- 어반정식 A 35,000원\n- 어반정식 B 55,000원\n[이용 시간] 정보 없음\n[휴무일] 연중무휴\n[문의처] 062-674-0100\n\n[소개]\n상세 소개 정보가 준비 중입니다.','2026-05-19 02:21:38','',NULL,NULL),(1140,'술술센터','서울특별시','서울특별시 영등포구 도림로133길 15 (문래동2가)','20260101',NULL,'https://tong.visitkorea.or.kr/cms/resource/22/4063722_image2_1.jpg','전시','정보 없음','02-2634-2220','[이용 요금] 정보 없음\n[이용 시간] 정보 없음\n[휴무일] 매주 월요일 / 공휴일\n[문의처] 02-2634-2220\n\n[소개]\n상세 소개 정보가 준비 중입니다.','2026-05-19 02:21:43','',NULL,NULL),(1141,'X:PORT 엑스포트 인천국제공항 디지털전시체험관','인천광역시','인천광역시 중구 공항로 271 (운서동)','20260101',NULL,'https://tong.visitkorea.or.kr/cms/resource/16/4064516_image2_1.jpg','체험','무료','운영사무국 032-741-3289','[이용 요금] 무료\n[이용 시간] 정보 없음\n[휴무일] 연중무휴\n[문의처] 운영사무국 032-741-3289\n\n[소개]\n상세 소개 정보가 준비 중입니다.','2026-05-19 02:21:47','',NULL,NULL),(1142,'아이와즈','광주광역시','광주광역시 광산구 상완길 71 (수완동)','20260101',NULL,'https://tong.visitkorea.or.kr/cms/resource/37/4064037_image2_1.jpg','전시','리얼월드 20,000원\n※ 